import { useEffect, useRef, useState } from "react";

const KART_B64 = "";

export default function IntroLoader({ onComplete }) {
  const canvasRef = useRef(null);
  const [done, setDone] = useState(false);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");

    const W = canvas.width = window.innerWidth;
    const H = canvas.height = window.innerHeight;

    // Load kart image
    const kartImg = new Image();
    kartImg.src = "data:image/png;base64," + KART_B64;

    kartImg.onload = () => {
      // Kart dimensions — scale to ~30% screen width
      const kartW = Math.min(W * 0.30, 340);
      const kartH = kartImg.naturalHeight * (kartW / kartImg.naturalWidth);

      // Animation state
      let frame = 0;
      const FPS = 60;
      const T = (s) => Math.round(s * FPS); // frames

      // Phases (in frames)
      const IDLE_END    = T(0.8);   // spinning tires + smoke
      const BAR_END     = T(1.2);   // bar fades in
      const LAUNCH_END  = T(2.2);   // kart launches off screen
      const FLAG_START  = T(2.1);
      const FLAG_END    = T(2.8);
      const TOTAL       = T(3.0);

      // Smoke particles
      const particles = [];
      const MAX_PARTICLES = 60;

      function addSmoke(x, y) {
        if (particles.length > MAX_PARTICLES) return;
        particles.push({
          x, y,
          vx: (Math.random() - 0.6) * 0.8,
          vy: -(Math.random() * 1.2 + 0.3),
          life: 1.0,
          decay: Math.random() * 0.015 + 0.01,
          r: Math.random() * 12 + 6,
        });
      }

      function updateParticles() {
        for (let i = particles.length - 1; i >= 0; i--) {
          const p = particles[i];
          p.x += p.vx;
          p.y += p.vy;
          p.life -= p.decay;
          p.r += 0.3;
          if (p.life <= 0) particles.splice(i, 1);
        }
      }

      function drawParticles() {
        for (const p of particles) {
          ctx.save();
          ctx.globalAlpha = p.life * 0.35;
          ctx.fillStyle = "#ffffff";
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
          ctx.fill();
          ctx.restore();
        }
      }

      // Ease functions
      const easeIn  = (t) => t * t * t;
      const easeOut = (t) => 1 - Math.pow(1 - t, 3);

      let animId;

      function render() {
        ctx.clearRect(0, 0, W, H);

        // Black background
        ctx.fillStyle = "#000000";
        ctx.fillRect(0, 0, W, H);

        // --- KART POSITION ---
        const kartY = H * 0.52 - kartH / 2;
        const startX = W * 0.12;

        let kartX = startX;
        let kartAlpha = 1;

        if (frame < IDLE_END) {
          // Idle: subtle bounce
          kartX = startX + Math.sin(frame * 0.25) * 1.5;

        } else if (frame < LAUNCH_END) {
          // Launch: eased acceleration to off-screen right
          const t = (frame - BAR_END) / (LAUNCH_END - BAR_END);
          const ease = easeIn(Math.max(0, t));
          kartX = startX + ease * (W * 1.1 - startX);
          // Fade out near end
          if (t > 0.8) kartAlpha = 1 - (t - 0.8) / 0.2;
        } else {
          kartX = W * 1.2;
          kartAlpha = 0;
        }

        // Rear-wheel position (roughly 25% from left of kart, vertically at bottom 40%)
        const rearWheelX = kartX + kartW * 0.22;
        const rearWheelY = kartY + kartH * 0.78;

        // --- SMOKE ---
        if (frame < LAUNCH_END - T(0.3)) {
          const smCount = frame < IDLE_END ? 2 : 4;
          for (let i = 0; i < smCount; i++) {
            addSmoke(
              rearWheelX + (Math.random() - 0.5) * 20,
              rearWheelY + (Math.random() - 0.5) * 8
            );
          }
        }
        updateParticles();

        // --- PROGRESS BAR ---
        const barY = kartY + kartH * 0.88;
        const barH = 4;
        const barStartX = W * 0.04;
        const barEndX   = W * 0.96;
        const barTotalW = barEndX - barStartX;

        if (frame >= T(0.6)) {
          const barFadeT = Math.min(1, (frame - T(0.6)) / T(0.3));

          // Track
          ctx.save();
          ctx.globalAlpha = 0.25 * barFadeT;
          ctx.fillStyle = "#555";
          ctx.beginPath();
          ctx.roundRect(barStartX, barY, barTotalW, barH, barH / 2);
          ctx.fill();
          ctx.restore();

          // Fill — tracks kart nose
          if (frame < LAUNCH_END) {
            const fillW = Math.max(0, Math.min(barTotalW, kartX + kartW - barStartX - kartW * 0.05));
            if (fillW > 0) {
              const grad = ctx.createLinearGradient(barStartX, 0, barStartX + fillW, 0);
              grad.addColorStop(0, "#8B6520");
              grad.addColorStop(0.7, "#AE822B");
              grad.addColorStop(1, "#F0D080");
              ctx.save();
              ctx.globalAlpha = barFadeT;
              ctx.fillStyle = grad;
              ctx.beginPath();
              ctx.roundRect(barStartX, barY, fillW, barH, barH / 2);
              ctx.fill();

              // Leading glint
              ctx.globalAlpha = barFadeT * 0.9;
              const glintGrad = ctx.createRadialGradient(barStartX + fillW, barY + barH/2, 0, barStartX + fillW, barY + barH/2, 14);
              glintGrad.addColorStop(0, "rgba(255,230,120,0.9)");
              glintGrad.addColorStop(1, "rgba(255,230,120,0)");
              ctx.fillStyle = glintGrad;
              ctx.fillRect(barStartX + fillW - 14, barY - 6, 28, barH + 12);
              ctx.restore();
            }
          } else {
            // Bar complete
            const grad = ctx.createLinearGradient(barStartX, 0, barEndX, 0);
            grad.addColorStop(0, "#8B6520");
            grad.addColorStop(1, "#AE822B");
            ctx.save();
            ctx.globalAlpha = barFadeT;
            ctx.fillStyle = grad;
            ctx.beginPath();
            ctx.roundRect(barStartX, barY, barTotalW, barH, barH / 2);
            ctx.fill();
            ctx.restore();
          }
        }

        // --- DRAW SMOKE (under kart) ---
        drawParticles();

        // --- SPEED LINES (during launch) ---
        if (frame >= BAR_END && frame < LAUNCH_END) {
          const t = (frame - BAR_END) / (LAUNCH_END - BAR_END);
          ctx.save();
          ctx.globalAlpha = easeIn(t) * 0.5;
          ctx.strokeStyle = "#ffffff";
          ctx.lineWidth = 1;
          for (let i = 0; i < 10; i++) {
            const ly = H * (0.3 + Math.random() * 0.4);
            const lx2 = kartX - 10;
            const lx1 = lx2 - (60 + Math.random() * 120) * easeIn(t);
            ctx.globalAlpha = easeIn(t) * (0.15 + Math.random() * 0.2);
            ctx.beginPath();
            ctx.moveTo(lx1, ly);
            ctx.lineTo(lx2, ly);
            ctx.stroke();
          }
          ctx.restore();
        }

        // --- DRAW KART ---
        if (kartAlpha > 0) {
          ctx.save();
          ctx.globalAlpha = kartAlpha;

          // Motion blur during launch: ghost copies
          if (frame >= BAR_END && frame < LAUNCH_END) {
            const t = (frame - BAR_END) / (LAUNCH_END - BAR_END);
            const blurCount = Math.floor(easeIn(t) * 5);
            const blurStep = easeIn(t) * 30;
            for (let b = blurCount; b > 0; b--) {
              ctx.globalAlpha = kartAlpha * (1 - b / blurCount) * 0.18;
              ctx.drawImage(kartImg, kartX - b * blurStep, kartY, kartW, kartH);
            }
            ctx.globalAlpha = kartAlpha;
          }

          ctx.drawImage(kartImg, kartX, kartY, kartW, kartH);
          ctx.restore();
        }

        // --- CHECKERED FLAG WIPE ---
        if (frame >= FLAG_START) {
          const t = Math.min(1, (frame - FLAG_START) / (FLAG_END - FLAG_START));
          const ease = easeOut(t);
          const wipeX = ease * (W + 80) - 80; // left edge of the flag

          const sq = 40; // square size
          const cols = Math.ceil(W / sq) + 2;
          const rows = Math.ceil(H / sq) + 1;

          ctx.save();
          for (let row = 0; row < rows; row++) {
            for (let col = 0; col < cols; col++) {
              const x = wipeX + col * sq;
              const y = row * sq;
              if (x > W) continue;
              const isBlack = (row + col) % 2 === 0;
              ctx.fillStyle = isBlack ? "#000000" : "#ffffff";
              ctx.fillRect(x, y, sq, sq);
            }
          }
          ctx.restore();

          // Full coverage once done
          if (t >= 1) {
            ctx.fillStyle = "#000000";
            ctx.fillRect(0, 0, W, H);
          }
        }

        frame++;
        if (frame < TOTAL) {
          animId = requestAnimationFrame(render);
        } else {
          setDone(true);
          onComplete && onComplete();
        }
      }

      animId = requestAnimationFrame(render);
      return () => cancelAnimationFrame(animId);
    };
  }, [onComplete]);

  if (done) return null;

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 9999,
        background: "#000",
        overflow: "hidden",
      }}
    >
      <canvas ref={canvasRef} style={{ display: "block", width: "100%", height: "100%" }} />
    </div>
  );
}